def retry(max_attempts=3, delay=1.0):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            attempts = 0
            last_exception = None

            while attempts < max_attempts:
                attempts += 1
                try:
                    # Attempt to call the function
                    return func(*args, **kwargs)
                except Exception as e:
                    last_exception = e

